    55→static pthread_mutex_t g_handle_lock = PTHREAD_MUTEX_INITIALIZER;
    56→static pthread_mutex_t g_switch_lock = PTHREAD_MUTEX_INITIALIZER;
    57→static constexpr int kExceptionSignals[] = {
    58→    SIGSEGV, SIGABRT, SIGFPE, SIGILL, SIGBUS, SIGTRAP
    59→};
    60→static constexpr int kNumHandledSignals = sizeof(kExceptionSignals) / sizeof(kExceptionSignals[0]);
    61→static struct sigaction g_restore_action[kNumHandledSignals] = {0};
    62→static bool handlers_installed = false;
    63→
    64→static bool isZygoteProcess() {
    65→    char cmdline[128] = {0};
    66→    FILE* fp = fopen("/proc/self/cmdline", "r");
    67→    if (fp) {
    68→        size_t n = fread(cmdline, 1, sizeof(cmdline) - 1, fp);
    69→        if (n > 0) cmdline[n] = '\0';
    70→        fclose(fp);
    71→        if (strstr(cmdline, "zygote") != nullptr) {
    72→            return true;
    73→        }
    74→    }
    75→    return false;
    76→}
    77→
    78→void Opencore::HandleSignal(int signal, siginfo_t* siginfo, void* ucontext_raw) {
    79→    pthread_mutex_lock(&g_handle_lock);
    80→    Disable();
    81→    Dump(siginfo, ucontext_raw);
    82→    raise(signal);
    83→    pthread_mutex_unlock(&g_handle_lock);
    84→}
    85→
    86→bool Opencore::Enable() {
    87→    if (isZygoteProcess()) {
    88→        JNI_LOGI("Skip opencore in zygote process");
    89→        return false;
    90→    }
    91→    pthread_mutex_lock(&g_switch_lock);
    92→    if (handlers_installed) {
    93→        JNI_LOGW("opencore native handlers already installed.");
    94→        pthread_mutex_unlock(&g_switch_lock);
    95→        return false;
    96→    }
    97→
    98→    for (int i = 0; i < kNumHandledSignals; ++i) {
    99→        if (sigaction(kExceptionSignals[i], NULL, &g_restore_action[i]) == -1) {
   100→            JNI_LOGE("signal %d unable to store old handler", kExceptionSignals[i]);
   101→            pthread_mutex_unlock(&g_switch_lock);
   102→            return false;
   103→        }
   104→    }
   105→
   106→    struct sigaction stact;
   107→    memset(&stact, 0, sizeof(stact));
   108→    sigemptyset(&stact.sa_mask);
   109→
   110→    for (int i = 0; i < kNumHandledSignals; ++i)
   111→        sigaddset(&stact.sa_mask, kExceptionSignals[i]);
   112→
   113→    stact.sa_sigaction = Opencore::HandleSignal;
   114→    stact.sa_flags = SA_RESTART | SA_SIGINFO | SA_ONSTACK;
   115→
   116→    for (int i = 0; i < kNumHandledSignals; i++)
   117→        sigaction(kExceptionSignals[i], &stact, NULL);
   118→
   119→    handlers_installed = true;
   120→    pthread_mutex_unlock(&g_switch_lock);
   121→    return true;
   122→}
   123→
   124→bool Opencore::Disable() {
   125→    pthread_mutex_lock(&g_switch_lock);
   126→    if (!handlers_installed) {
   127→        JNI_LOGW("opencore native handlers already uninstalled.");
   128→        pthread_mutex_unlock(&g_switch_lock);
   129→        return false;
   130→    }
   131→
   132→    for (int i = 0; i < kNumHandledSignals; i++)
   133→        sigaction(kExceptionSignals[i], &g_restore_action[i], NULL);
   134→
   135→    memset(&g_restore_action, 0, sizeof(g_restore_action));
   136→    handlers_installed = false;
   137→    pthread_mutex_unlock(&g_switch_lock);
   138→    return true;
   139→}
   140→
   141→bool Opencore::IsEnabled() {
   142→    bool installed = false;
   143→    pthread_mutex_lock(&g_switch_lock);
   144→    installed = handlers_installed;
   145→    pthread_mutex_unlock(&g_switch_lock);
   146→    return installed;
   147→}
