   149→void Opencore::IgnoreHandler() {
   150→    // only child process use
   151→    struct sigaction stact;
   152→    memset(&stact, 0, sizeof(stact));
   153→    stact.sa_handler = SIG_IGN;
   154→    stact.sa_flags = SA_RESTART;
   155→    sigaction(SIGCHLD, &stact, NULL);
   156→
   157→    // ignore opencore signal handler
   158→    for (int i = 0; i < kNumHandledSignals; i++)
   159→        sigaction(kExceptionSignals[i], &stact, NULL);
   160→}
