   256→
   257→void Opencore::Dump(Opencore::DumpOption* option) {
   258→    if (!option || !option->pid) {
   259→        JNI_LOGE("No any dump!");
   260→        return;
   261→    }
   262→
   263→    int ori_dumpable;
   264→    int flag, pid, tid;
   265→    char comm[16];
   266→    bool need_split = false;
   267→    bool need_restore_dumpable = false;
   268→    bool need_restore_ptrace = false;
   269→    std::string output;
   270→
   271→    Opencore* impl = GetInstance();
   272→    if (impl) {
   273→        impl->setPid(option->pid);
   274→        impl->setTid(option->tid);
   275→        impl->setSignalInfo(option->siginfo);
   276→
   277→        if (impl->getFilter() & FILTER_SIGNAL_CONTEXT)
   278→            impl->setContext(option->context);
   279→
   280→        pid = impl->getPid();
   281→        tid = impl->getTid();
   282→        flag = impl->getFlag();
   283→
   284→        if (impl->getDir().length() > 0) {
   285→            output.append(impl->getDir()).append("/");
   286→        }
   287→        if (!option->filename) {
   288→            if (!(flag & FLAG_ALL)) {
   289→                flag |= FLAG_CORE;
   290→                flag |= FLAG_TID;
   291→            }
   292→
   293→            if (flag & FLAG_CORE)
   294→                output.append("core.");
   295→
   296→            if (flag & FLAG_PROCESS_COMM) {
   297→                char comm_path[32];
   298→                snprintf(comm_path, sizeof(comm_path), "/proc/%d/comm", pid);
   299→                int fd = open(comm_path, O_RDONLY);
   300→                if (fd > 0) {
   301→                    memset(&comm, 0x0, sizeof(comm));
   302→                    int rc = read(fd, &comm, sizeof(comm) - 1);
   303→                    if (rc > 0) {
   304→                        for (int i = 0; i < rc; i++) {
   305→                            if (comm[i] == '\n') {
   306→                                comm[i] = 0;
   307→                                break;
   308→                            }
   309→                        }
   310→                        comm[rc] = 0;
   311→                        output.append(comm);
   312→                    } else {
   313→                        output.append("unknown");
   314→                    }
   315→                    close(fd);
   316→                }
   317→                need_split = true;
   318→            }
   319→
   320→            if (flag & FLAG_PID) {
   321→                if (need_split)
   322→                    output.append("_");
   323→                output.append(std::to_string(pid));
   324→                need_split = true;
   325→            }
   326→
   327→            if (flag & FLAG_THREAD_COMM) {
   328→                if (need_split)
   329→                    output.append("_");
   330→
   331→                char thread_comm_path[64];
   332→                snprintf(thread_comm_path, sizeof(thread_comm_path), "/proc/%d/task/%d/comm", pid, tid);
   333→                int fd = open(thread_comm_path, O_RDONLY);
   334→                if (fd > 0) {
   335→                    memset(&comm, 0x0, sizeof(comm));
   336→                    int rc = read(fd, &comm, sizeof(comm) - 1);
   337→                    if (rc > 0) {
   338→                        for (int i = 0; i < rc; i++) {
   339→                            if (comm[i] == '\n') {
   340→                                comm[i] = 0;
   341→                                break;
   342→                            }
   343→                        }
   344→                        comm[rc] = 0;
   345→                        output.append(comm);
   346→                    } else {
   347→                        output.append("unknown");
   348→                    }
   349→                    close(fd);
   350→                }
   351→                need_split = true;
   352→            }
   353→
   354→            if (flag & FLAG_TID) {
   355→                if (need_split)
   356→                    output.append("_");
   357→                output.append(std::to_string(tid));
   358→                need_split = true;
   359→            }
   360→
   361→            if (flag & FLAG_TIMESTAMP) {
   362→                struct timeval tv;
   363→                gettimeofday(&tv, NULL);
   364→                if (need_split)
   365→                    output.append("_");
   366→                output.append(std::to_string(tv.tv_sec));
   367→            }
   368→        } else {
   369→            output.append(option->filename);
   370→        }
   371→
   372→        ori_dumpable = prctl(PR_GET_DUMPABLE);
   373→        if (!prctl(PR_SET_DUMPABLE, 1))
   374→            need_restore_dumpable = true;
   375→
   376→        if (!prctl(PR_SET_PTRACER, PR_SET_PTRACER_ANY))
   377→            need_restore_ptrace = true;
   378→
   379→        impl->Coredump(output.c_str());
   380→
   381→        if (need_restore_dumpable) prctl(PR_SET_DUMPABLE, ori_dumpable);
   382→        if (need_restore_ptrace) prctl(PR_SET_PTRACER, 0);
   383→
   384→        DumpCallback callback = impl->getCallback();
   385→        if (callback) callback(output.c_str());
   386→    } else {
   387→        JNI_LOGI("Not support coredump!!");
   388→    }
   389→}
