   391→bool Opencore::Coredump(const char* filename) {
   392→    pid_t child = fork();
   393→    if (child == 0) {
   394→        IgnoreHandler();
   395→        signal(SIGALRM, Opencore::TimeoutHandle);
   396→        alarm(getTimeout());
   397→        DoCoredump(filename);
   398→        Finish();
   399→        _exit(0);
   400→    } else {
   401→        JNI_LOGI("Wait (%d) coredump", child);
   402→        int status = 0;
   403→        wait(&status);
   404→    }
   405→    return true;
   406→}
   407→
   408→void Opencore::Finish() {
   409→    Continue();
   410→    maps.clear();
   411→    setContext(nullptr);
   412→    setSignalInfo(nullptr);
   413→}
