   415→int Opencore::IsFilterSegment(Opencore::VirtualMemoryArea& vma) {
   416→    int filter = getFilter();
   417→    if (filter & FILTER_SPECIAL_VMA) {
   418→        if (vma.file == "/dev/binderfs/hwbinder"
   419→                || vma.file == "/dev/binderfs/binder"
   420→                || vma.file == "[vvar]"
   421→                || vma.file == "/dev/mali0"
   422→           ) {
   423→            return VMA_NULL;
   424→        }
   425→    }
   426→
   427→    if (filter & FILTER_FILE_VMA) {
   428→        if (vma.inode > 0 && vma.flags[1] == '-')
   429→            return NeedFilterFile(vma);
   430→    }
   431→
   432→    if (filter & FILTER_SHARED_VMA) {
   433→        if (vma.flags[3] == 's' || vma.flags[3] == 'S')
   434→            return VMA_NULL;
   435→    }
   436→
   437→    if (filter & FILTER_SANITIZER_SHADOW_VMA) {
   438→        if (vma.file == "[anon:low shadow]"
   439→                || vma.file == "[anon:high shadow]"
   440→                || (vma.file.compare(0, 12, "[anon:hwasan") == 0))
   441→            return VMA_NULL;
   442→    }
   443→
   444→    if (filter & FILTER_NON_READ_VMA) {
   445→        if (vma.flags[0] == '-' && vma.flags[1] == '-' && vma.flags[2] == '-')
   446→            return VMA_NULL;
   447→    }
   448→
   449→    if (filter & FILTER_JAVAHEAP_VMA) {
   450→        if (vma.file.compare(0, 12, "[anon:dalvik") == 0)
   451→            return VMA_NULL;
   452→    }
   453→
   454→    if (filter & FILTER_JIT_CACHE_VMA) {
   455→        if (vma.file.compare(0, 10, "/memfd:jit") == 0)
   456→            return VMA_NULL;
   457→    }
   458→    return VMA_NORMAL;
   459→}
