   461→void Opencore::StopTheWorld(int pid) {
   462→    char task_dir[32];
   463→    struct dirent *entry;
   464→    snprintf(task_dir, sizeof(task_dir), "/proc/%d/task", pid);
   465→    DIR *dp = opendir(task_dir);
   466→    if (dp) {
   467→        while ((entry=readdir(dp)) != NULL) {
   468→            if (!strncmp(entry->d_name, ".", 1)) {
   469→                continue;
   470→            }
   471→
   472→            pid_t tid = std::atoi(entry->d_name);
   473→            Opencore::StopTheThread(tid);
   474→        }
   475→        closedir(dp);
   476→    }
   477→}
   478→
   479→bool Opencore::StopTheThread(int tid) {
   480→    ThreadRecord ts = {
   481→        .pid = tid,
   482→        .attached = false,
   483→    };
   484→    if (ptrace(PTRACE_ATTACH, tid, NULL, 0) < 0) {
   485→        threads.push_back(ts);
   486→        return false;
   487→    }
   488→
   489→    ts.attached = true;
   490→    threads.push_back(ts);
   491→
   492→    int status = 0;
   493→    int result = waitpid(tid, &status, WUNTRACED | __WALL);
   494→    if (result != tid) {
   495→        JNI_LOGW("waitpid failed on %d while detaching", tid);
   496→        return false;
   497→    }
   498→    if (WIFSTOPPED(status)) {
   499→        int received_signal = 0;
   500→        if (status >> 16 == PTRACE_EVENT_STOP) {
   501→            received_signal = 0;
   502→        } else {
   503→            received_signal = WSTOPSIG(status);
   504→        }
   505→        return true;
   506→    }
   507→    JNI_LOGW("waitpid failed on %d while non-stop, status 0x%x", tid, status);
   508→    return false;
   509→}
   510→
   511→void Opencore::Continue() {
   512→    for (int index = 0; index < threads.size(); index++) {
   513→        ThreadRecord& ts = threads[index];
   514→        if (!ts.attached)
   515→            continue;
   516→
   517→        pid_t tid = ts.pid;
   518→        if (ptrace(PTRACE_DETACH, tid, NULL, 0) < 0)
   519→            continue;
   520→    }
   521→    threads.clear();
   522→}
