   524→void Opencore::ParseMaps(int pid, std::vector<VirtualMemoryArea>& maps) {
   525→    char filename[32];
   526→    char line[1024];
   527→
   528→    snprintf(filename, sizeof(filename), "/proc/%d/maps", pid);
   529→    FILE *fp = fopen(filename, "r");
   530→    if (fp) {
   531→        while (fgets(line, sizeof(line), fp)) {
   532→            int m;
   533→            VirtualMemoryArea vma;
   534→            char filename[256] = {'\0'};
   535→
   536→
   537→            sscanf(line, "%" PRIx64 "-%" PRIx64 " %c%c%c%c %x %x:%x  %" PRIu64 "  %[^\n] %n",
   538→                   &vma.begin, &vma.end,
   539→                   &vma.flags[0], &vma.flags[1], &vma.flags[2], &vma.flags[3],
   540→                   &vma.offset, &vma.major, &vma.minor, &vma.inode, filename, &m);
   541→
   542→            vma.file = filename;
   543→
   544→#if defined(__i386__) || defined(__x86__) || defined(__arm__)
   545→            // avoid compat32 bit application dump64
   546→            if (vma.begin > 0xFFFFFFFF)
   547→                break;
   548→#endif
   549→            maps.push_back(vma);
   550→        }
   551→        fclose(fp);
   552→    }
   553→}
