    return Opencore::IsEnabled();
}

static jstring penguin_opencore_sdk_Coredump_nativeGetDir(JNIEnv* env, jclass /*clazz*/) {
    const char* dir = Opencore::GetDir();
    return env->NewStringUTF(dir);
}

