#ifndef OPENCORE_ARM64_OPENCORE_IMPL_H_
#define OPENCORE_ARM64_OPENCORE_IMPL_H_

#include "opencore/lp64/opencore.h"

namespace arm64 {

struct pt_regs {
    uint64_t  regs[31];
    uint64_t  sp;
    uint64_t  pc;
    uint64_t  pstate;
};

typedef struct elf64_prstatus {
    uint32_t             pr_si_signo;
    uint32_t             pr_si_code;
    uint32_t             pr_si_errno;
    uint16_t             pr_cursig;
    uint64_t             pr_sigpend;
    uint64_t             pr_sighold;
    uint32_t             pr_pid;
    uint32_t             pr_ppid;
    uint32_t             pr_pgrp;
    uint32_t             pd_sid;
    uint64_t             pr_utime[2];
    uint64_t             pr_stime[2];
    uint64_t             pr_cutime[2];
    uint64_t             pr_cstime[2];
    struct pt_regs       pr_reg;
    uint32_t             pr_fpvalid;
} Elf64_prstatus;

struct fpsimd_state {
    uint64_t    vregs[64]; // __uint128_t vregs[32]
    uint32_t    fpsr;
    uint32_t    fpcr;
    uint32_t    __reserved[2];
};

typedef struct elf64_fpregset {
    struct fpsimd_state regs;
} Elf64_fpregset;

struct tls {
    uint64_t tpidr_el0;
    uint64_t tpidr2_el0;
};

typedef struct elf64_tls {
    struct tls regs;
} Elf64_tls;

class Opencore : public lp64::OpencoreImpl {
public:
    Opencore() : lp64::OpencoreImpl() {}
    void Finish();
    void CreateCorePrStatus(int pid);
    void WriteCorePrStatus(FILE* fp);
    int IsSpecialFilterSegment(Opencore::VirtualMemoryArea& vma);
    void WriteCoreFpRegs(int tid, FILE* fp);
    void WriteCoreTLS(int tid, FILE* fp);
    void WriteCorePAC(int tid, FILE* fp);
    void WriteCoreMTE(int tid, FILE* fp);
    int getMachine() { return EM_AARCH64; }
private:
    std::vector<Elf64_prstatus> prstatus;
};

} // namespace arm64

#endif // OPENCORE_ARM64_OPENCORE_IMPL_H_

