    33→void OpencoreImpl::ParserPhdr(int index, Opencore::VirtualMemoryArea& vma) {
    34→    phdr[index].p_type = PT_LOAD;
    35→
    36→    phdr[index].p_vaddr = (Elf64_Addr)vma.begin;
    37→    phdr[index].p_paddr = 0x0;
    38→    phdr[index].p_memsz = (Elf64_Addr)vma.end-(Elf64_Addr)vma.begin;
    39→
    40→    if (vma.flags[0] == 'r' || vma.flags[0] == 'R')
    41→        phdr[index].p_flags = phdr[index].p_flags | PF_R;
    42→
    43→    if (vma.flags[1] == 'w' || vma.flags[1] == 'W')
    44→        phdr[index].p_flags = phdr[index].p_flags | PF_W;
    45→
    46→    if (vma.flags[2] == 'x' || vma.flags[2] == 'X')
    47→        phdr[index].p_flags = phdr[index].p_flags | PF_X;
    48→
    49→    phdr[index].p_filesz = phdr[index].p_memsz;
    50→    phdr[index].p_align = align_size;
    51→}
    52→
    53→void OpencoreImpl::ParserNtFile(int index, Opencore::VirtualMemoryArea& vma) {
    54→    file[index].begin = (Elf64_Addr)vma.begin;
    55→    file[index].end = (Elf64_Addr)vma.end;
    56→    file[index].offset = vma.offset >> 12;
    57→    fileslen += vma.file.length() + 1;
    58→}
    59→
    60→void OpencoreImpl::ParseProcessMapsVma(int pid) {
    61→    ParseMaps(pid, maps);
    62→    if (!maps.size())
    63→        return;
    64→
    65→    phdr.assign(maps.size(), {});
    66→    file.assign(maps.size(), {});
    67→
    68→    for (int index = 0; index < maps.size(); ++index) {
    69→        Opencore::VirtualMemoryArea& vma = maps[index];
    70→        ParserPhdr(index, vma);
    71→        ParserNtFile(index, vma);
    72→    }
    73→}
    74→
    75→void OpencoreImpl::CreateCoreHeader() {
    76→    snprintf((char *)ehdr.e_ident, 5, ELFMAG);
    77→    ehdr.e_ident[EI_CLASS] = ELFCLASS64;
    78→    ehdr.e_ident[EI_DATA] = ELFDATA2LSB;
    79→    ehdr.e_ident[EI_VERSION] = EV_CURRENT;
    80→
    81→    ehdr.e_type = ET_CORE;
    82→    ehdr.e_machine = getMachine();
    83→    ehdr.e_version = EV_CURRENT;
    84→    ehdr.e_entry = 0x0;
    85→    ehdr.e_phoff = sizeof(Elf64_Ehdr);
    86→    ehdr.e_shoff = 0x0;
    87→    ehdr.e_flags = 0x0;
    88→    ehdr.e_ehsize = sizeof(Elf64_Ehdr);
    89→    ehdr.e_phentsize = sizeof(Elf64_Phdr);
    90→    ehdr.e_phnum = (int)phdr.size() + 1;
    91→    ehdr.e_shentsize = 0x0;
    92→    ehdr.e_shnum = 0x0;
    93→    ehdr.e_shstrndx = 0x0;
    94→}
    95→
    96→void OpencoreImpl::CreateCoreNoteHeader() {
    97→    note.p_type = PT_NOTE;
    98→    note.p_offset = sizeof(Elf64_Ehdr) + ehdr.e_phnum * sizeof(Elf64_Phdr);
    99→}
   100→
   101→void OpencoreImpl::CreateCoreAUXV(int pid) {
   102→    char filename[32];
   103→    lp64::Auxv vec;
   104→    snprintf(filename, sizeof(filename), "/proc/%d/auxv", pid);
   105→
   106→    FILE *fp = fopen(filename, "rb");
   107→    if (fp != nullptr) {
   108→        while (fread(&vec, sizeof(vec), 1, fp)) {
   109→            auxvnum++;
   110→        }
   111→        fseek(fp, 0, SEEK_SET);
   112→
   113→        auxv.assign(auxvnum, {});
   114→
   115→        int index =0;
   116→        while (fread(&vec, sizeof(vec), 1, fp)) {
   117→            auxv[index].type = vec.type;
   118→            auxv[index].value = vec.value;
   119→            index++;
   120→        }
   121→
   122→        fclose(fp);
   123→    }
   124→}
   125→
   126→void OpencoreImpl::SpecialCoreFilter() {
   127→    for (int index = 0; index < maps.size(); ++index) {
   128→        Opencore::VirtualMemoryArea& vma = maps[index];
   129→        int vma_flag = IsFilterSegment(vma) | IsSpecialFilterSegment(vma);
   130→        if (vma_flag & VMA_NULL)
   131→            phdr[index].p_filesz = 0x0;
   132→
   133→        if (vma_flag & VMA_INCLUDE)
   134→            phdr[index].p_filesz = phdr[index].p_memsz;
   135→    }
   136→}
   137→
   138→void OpencoreImpl::WriteCoreHeader(FILE* fp) {
   139→    fwrite((void *)&ehdr, sizeof(Elf64_Ehdr), 1, fp);
   140→}
   141→
   142→void OpencoreImpl::WriteCoreNoteHeader(FILE* fp) {
   143→    note.p_filesz += sizeof(lp64::Auxv) * auxvnum + sizeof(Elf64_Nhdr) + 8;
   144→    note.p_filesz += extra_note_filesz;
   145→    note.p_filesz += sizeof(lp64::File) * phdr.size() + sizeof(Elf64_Nhdr) + 8 + 2 * 8 + RoundUp(fileslen, 4);
   146→    fwrite((void *)&note, sizeof(Elf64_Phdr), 1, fp);
   147→}
   148→
   149→void OpencoreImpl::WriteCoreProgramHeaders(FILE* fp) {
   150→    if (phdr.empty())
   151→        return;
   152→
   153→    int phnum = (int)phdr.size();
   154→    uint64_t offset = RoundUp(note.p_offset + note.p_filesz, align_size);
   155→    phdr[0].p_offset = offset;
   156→    fwrite(&phdr[0], sizeof(Elf64_Phdr), 1, fp);
   157→
   158→    int index = 1;
   159→    while (index < phnum) {
   160→        phdr[index].p_offset = phdr[index - 1].p_offset + phdr[index-1].p_filesz;
   161→        fwrite(&phdr[index], sizeof(Elf64_Phdr), 1, fp);
   162→        index++;
   163→    }
   164→}
   165→
   166→void OpencoreImpl::WriteCoreSignalInfo(FILE* fp) {
   167→    Elf64_Nhdr elf_nhdr;
   168→    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
   169→    elf_nhdr.n_descsz = sizeof(siginfo_t);
   170→    elf_nhdr.n_type = NT_SIGINFO;
   171→
   172→    char magic[8];
   173→    memset(magic, 0, sizeof(magic));
   174→    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
   175→
   176→    fwrite(&elf_nhdr, sizeof(Elf64_Nhdr), 1, fp);
   177→    fwrite(magic, sizeof(magic), 1, fp);
   178→
   179→    siginfo_t info;
   180→    memset(&info, 0x0, sizeof(siginfo_t));
   181→    if (getSignalInfo())
   182→        memcpy(&info, getSignalInfo(), sizeof(siginfo_t));
   183→    fwrite(&info, sizeof(siginfo_t), 1, fp);
   184→}
   185→
   186→void OpencoreImpl::WriteCoreAUXV(FILE* fp) {
   187→    Elf64_Nhdr elf_nhdr;
   188→    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
   189→    elf_nhdr.n_descsz = sizeof(lp64::Auxv) * auxvnum;
   190→    elf_nhdr.n_type = NT_AUXV;
   191→
   192→    char magic[8];
   193→    memset(magic, 0, sizeof(magic));
   194→    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
   195→
   196→    fwrite(&elf_nhdr, sizeof(Elf64_Nhdr), 1, fp);
   197→    fwrite(magic, sizeof(magic), 1, fp);
   198→
   199→    int index = 0;
   200→    while (index < auxvnum) {
   201→        fwrite(&auxv[index], sizeof(lp64::Auxv), 1, fp);
   202→        index++;
   203→    }
   204→}
   205→
   206→void OpencoreImpl::WriteNtFile(FILE* fp) {
   207→    int phnum = (int)phdr.size();
   208→    Elf64_Nhdr elf_nhdr;
   209→    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
   210→    elf_nhdr.n_descsz = sizeof(lp64::File) * phnum + 2 * 8 + RoundUp(fileslen, 4);
   211→    elf_nhdr.n_type = NT_FILE;
   212→
   213→    char magic[8];
   214→    memset(magic, 0, sizeof(magic));
   215→    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
   216→
   217→    fwrite(&elf_nhdr, sizeof(Elf64_Nhdr), 1, fp);
   218→    fwrite(magic, sizeof(magic), 1, fp);
   219→
   220→    uint64_t number = phnum;
   221→    fwrite(&number, 8, 1, fp);
   222→    fwrite(&page_size, 8, 1, fp);
   223→
   224→    for (int index = 0; index < phnum; ++index)
   225→        fwrite(&file[index], sizeof(lp64::File), 1, fp);
   226→
   227→    for (int index = 0; index < phnum; ++index)
   228→        fwrite(maps[index].file.data(), maps[index].file.length() + 1, 1, fp);
   229→}
   230→
   231→void OpencoreImpl::AlignNoteSegment(FILE* fp) {
   232→    memset(zero.data(), 0x0, align_size);
   233→    uint64_t align_filesz = note.p_filesz - RoundUp(fileslen, 4) + fileslen;
   234→    uint64_t offset = RoundUp(note.p_offset + align_filesz, align_size);
   235→    uint64_t size = offset - (note.p_offset + align_filesz);
   236→    fwrite(zero.data(), size, 1, fp);
   237→}
